var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후우……. 총알값에 기름값 빼면 이번 의뢰도 또 적자군.","JPN":"ふう……弾代にガソリン代まで引かれたら今回の依頼も赤字だな。","ENG":"*Sigh* After excepting all the ammo and fuel used on this job, I'm in the red again.","TWN":"哀……彈藥的費用再扣掉油錢，這次的委託又沒賺錢！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"특수탄 단가를 더 줄여 봐야 하나?","JPN":"特殊弾の単価をもっと下げるべきか？","ENG":"Should I cut down on special bullets?","TWN":"還是要減少特殊彈的預算？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아냐, 더 줄이면 내 명줄이 더 빨리 줄어들 텐데…….","JPN":"いや、これ以上予算を削ったら俺の命も削られるな……","ENG":"But that'll surely shorten my lifespan.","TWN":"不行！再減少預算的話，我的壽命應該會減少得更快……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"왔어요, 사장님? 의뢰비는요?","JPN":"おかえりなさい、社長。報酬はちゃんともらってきました？","ENG":"Welcome back, Boss. Where's our payment?","TWN":"老闆你來啦，這次的委託費呢？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"넌 힘들게 일하고 온 사람한테 다짜고짜 돈 얘기부터 꺼내냐?","JPN":"あのな、苦労して仕事してきた人間にいきなり金の話か？","ENG":"I just came back from work. Shouldn't you ask me how my day was first?","TWN":"我在外面那麼辛苦地工作，你一見到我就只會討錢嗎？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"세상에 편하고 돈 잘 버는 일이 어디 있어요.","JPN":"このご時世、楽して稼げる仕事なんかありません。","ENG":"Oh, don't be a baby. There's no job that's easy and well-paid.","TWN":"世界上哪有什麼不辛苦的工作，"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그런 게 있어도 저희들 같은 인생에게는 T/O 안 떨어지거든요?","JPN":"もしあるとしても、私たちみたいな底辺傭兵には回って来ませんよ。","ENG":"If there is such an easy job, then it's not for us.","TWN":"就算有也輪不到我們啦～"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래? 내 눈앞에 있는 분은 벌써 한 자리 꿰어찬 모양인데?","JPN":"ふむ？　俺の目の前にいるお方は、すでにそんな仕事を見つけているようだが？","ENG":"Oh, yeah? I think you know all about easy jobs.","TWN":"是嗎？但現在在我眼前的這位小姐，工作似乎就滿輕鬆的？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"무슨 실례되는 말씀을. 사장님 안 계신 동안 가슴 졸이느라 혼났다고요.","JPN":"失礼な。社長がいない間一人でハラハラして大変だったんですよ？","ENG":"What are you talking about? I worried about you all day while you were out there. You think that's easy?","TWN":"老闆你說這種話良心不會痛嗎？老闆不在的時候，我有多辛苦你知道嗎？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아, 그러셔.","JPN":"へえ、そうか？","ENG":"Yeah, right.","TWN":"喔，是這樣喔？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그래서 의뢰비는요? 통장에는 입금된 게 없던데 직접 받아오신 거예요?","JPN":"で、報酬は？　振込履歴は無いので、直接手渡しでもらってきたんですか？","ENG":"So, where's our money? No new deposits in our bank account. Did you get a check?","TWN":"所以委託費呢？我看存摺沒有入帳，那應該是老闆直接收現金吧？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"훗. 나는 사업할 때 돈보다 공익을 우선하는 사람이야.","JPN":"フッ、俺は事業をするにあたって、金より公益を優先する人間でな。","ENG":"Hah. As a businessman, I value public interests more than my own monetary benefit.","TWN":"哼，我做生意最重視的是公益，錢只擺第二。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"아하. 또 앞뒤 생각 안 하고 그 비싼 특수탄을 있는 대로 쏟아 부으셨다고요?","JPN":"それで、また後先考えずあの高額な特殊弾にありったけつぎ込んできたんです？","ENG":"You mean you got carried away again and used all those expensive special bullets?","TWN":"哈，意思是你又因為逞一時之快，把那些昂貴的特殊彈全用光了對吧？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Kahem...","TWN":"呃……"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"진짜 한 푼도 못 건진 거예요?","JPN":"本当に1クレジットも残していないんですか？","ENG":"You didn't get anything? Anything at all?","TWN":"真的一毛不剩？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"한 푼도.","JPN":"ああ、無一文だ。","ENG":"No, not at all.","TWN":"一毛不剩。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"하아아아…….","JPN":"はああ……","ENG":"*Sigh...*","TWN":"哀哀哀……"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그러니까 더 늦기 전에 검법 배우시라니까요. 지금 배우면 강의료 30% 할인이래요.","JPN":"だからまだ間に合うんで、さっさと剣術を習ってきてくださいよ。今登録すれば受講料30％割引だそうですよ。","ENG":"I'm telling you, you should learn how to swing a sword before it's too late. You can get a 30 percent discount if you take the class now.","TWN":"就叫你趕快去學劍術，現在報名學費還打七折啦！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"야! 일반인이 칼 들고 침식체한테 덤비면 그냥 죽어!","JPN":"おいおい、一般人が剣を握って侵食体と戦ったところで死ぬだけだぞ！？","ENG":"Are you crazy? I'm not a Counter. Swinging a sword at C.O.s is suicidal!","TWN":"喂！你叫普通人拿把劍去對抗侵蝕體，這根本是叫他去送死吧！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……그런데 아까부터 혼자서 뭘 그렇게 먹고 있는 거야?","JPN":"……ところで、さっきから何をそんなに食べてるんだ？","ENG":"By the way, what are you eating all by yourself?","TWN":"……我在跟你說話，你嘴巴在那邊嚼嚼嚼，是在吃什麼？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"피자요. 한 조각 드려요?","JPN":"ピザです。1ピースいかがです？","ENG":"Pizza. Want a slice?","TWN":"我在吃披薩啊，老闆要來一片嗎？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"넌 사장이 현장에서 뛰고 있는데 피자가 목구멍으로 넘어가냐?","JPN":"社長は現場で必死に働いているのに、従業員はのんびりピザだとは。","ENG":"How could you eat pizza when your boss was out there, risking his life making us money?","TWN":"老闆在外面奔波，你還吃得下披薩？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"네. 치즈의 느끼한 맛을 할라피뇨의 매콤함이 잡아 줘서 술술 넘어가는 거 있죠?","JPN":"はい。チーズのくどい味をハラペーニョの辛さが抑えてくれて、手が止まりませんよ。","ENG":"Why not? It's good pizza. The jalapeño gives it just the right amount of heat to counter its cheesiness.","TWN":"吃得下啊，墨西哥辣椒整個綜合掉起司的油膩感，超涮嘴的！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"드시기 싫으시면 마세요.","JPN":"嫌なら食べなくてもいいです。","ENG":"If you don't want any, that's fine by me.","TWN":"不想吃就算啦～"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……한 조각 말고 두 조각만 줘. 아침에 시리얼 먹고 한 끼도 못 먹었어.","JPN":"……1ピースじゃ足りない、2ピースくれ。朝のシリアルだけで、1日まともに食えてないぞ。","ENG":"... I want two slices, not just one. I haven't eaten anything other than a bowl of cereal this morning.","TWN":"……一片不夠，給我兩片，我早上只有吃麥片而已。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"한 조각도 인심 써 드리는 거거든요. 저도 내기에 져서 섭섭하다고요.","JPN":"1ピースも大サービスなんですよ。私だって賭けに負けて落ち込んでいるんですから。","ENG":"I'm being generous by offering you a slice. I'm upset because I lost the bet.","TWN":"分你一片已經很好了，我打賭輸了，現在心情也不太美麗！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내기? 무슨 내기?","JPN":"賭け？　なんの賭けだ？","ENG":"Bet? What bet?","TWN":"打賭輸了？打什麼賭？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"자네가 빈털터리로 돌아올지 말지 였지.","JPN":"お前さんがすっからかんになって帰ってくるかどうかだ。","ENG":"We bet on whether you'd come back with money or not.","TWN":"賭你會不會空手而歸啊。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"거 봐, 아가씨. 내 말대로잖아.","JPN":"ほら、お嬢ちゃん。ワシの言うとおりだっただろ。","ENG":"See, lady? I told you.","TWN":"小姐，你看，我說的沒錯吧！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"저도 원래는 아저씨랑 같이 적자에 걸었잖아요.","JPN":"私だって元々おじいさんと一緒に赤字に賭けてたじゃないですか。","ENG":"I originally bet on the same side as you that he wouldn't.","TWN":"我本來也想跟你一樣賭空手而歸的，"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"둘 다 적자에 걸면 내기가 성립이 안 되니까 바꾼 거지.","JPN":"二人とも赤字に賭けたら賭けが成立しないから変えたんです。","ENG":"I changed it because the bet won't work if both bet on the same. ","TWN":"只是兩個人都賭同一個的話，沒辦法分出輸贏才換的！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"헴스워스 영감님이잖아? 말도 없이 여긴 또 왜 온 거야?","JPN":"ヘムズワース爺か。連絡もなくどうしたんだ？","ENG":"Helmsworth? What are you doing here?","TWN":"漢姆沃斯老頭？你怎麼又沒先跟我說一聲就跑來這裡？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이번에 밀린 대금은 분명 약속한 날짜까지 갚겠다고 했을 텐데.","JPN":"この前の未払い金は、約束した日付までに確かに返すと伝えたはずだが。","ENG":"I told you I'd pay off the overdue bills by the date we agreed upon.","TWN":"我不是說過之前欠的錢，這次一定會在約定期限內還你嗎！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"어떻게? 네 사업 수완으로?","JPN":"どうやって？　お前さんのその自慢の手腕でか？","ENG":"How? With your business skills?","TWN":"怎麼還？靠你的生意手腕嗎？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"잔말 말고 의뢰나 하나 처리해 와라. 그러면 외상은 탕감해 주지.","JPN":"言い訳も文句も言わねえで依頼を一件こなして来い。そうしたら今回の件はチャラにしてやる。","ENG":"Cut the crap and take my job. Then I'll write off your bills.","TWN":"廢話少說，你幫我處理一個委託，我們之間的債就一筆勾銷！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"부잣집 경호 의뢰?","JPN":"富豪の警護依頼？","ENG":"A bodyguard job for a rich client?","TWN":"去當豪宅的守衛？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그래. 옛날에 한 번 거래한 사이였는데 쓸 만한 용병을 소개해 달라더군.","JPN":"ああ。昔一度取引した仲なんだが、信用できる傭兵を紹介してほしいと言われてな。","ENG":"Yes. I had business with him once, and he asked me to introduce him to a competent mercenary.","TWN":"對啊，是我之前做生意認識的，對方請我介紹好用的傭兵給他。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"미안하지만 거절하겠어.","JPN":"悪いが断る。","ENG":"Sorry, no.","TWN":"不好意思，恕我拒絕。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"영감님 의뢰 맡았다가 죽을 뻔한 적이 한두 번이었어야지.","JPN":"あんたからの依頼で何度死にかけたことか。","ENG":"Jobs from you tend to end with me nearly dead.","TWN":"每次你的委託都差點把我搞到沒命！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"의뢰 대금은 확인하지 그래?","JPN":"依頼の手付金は確認したか？","ENG":"Why don't you check the price tag first?","TWN":"不如你先確認對方給的委託費吧？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"돈 때문에 사자굴로 기어 들어가는 취미는 없어서 말이야.","JPN":"金のために虎穴に入る趣味はないんでね。","ENG":"Nope. There's no amount of money that would make me enter the lion's den.","TWN":"我可不是那種為了錢連命都不要的人，"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"밀린 대금은 약속한 날짜에 어떻게든 갚지.","JPN":"滞納している代金は期日までには何とか返す。","ENG":"I'll give you your money like I promised.","TWN":"總之欠你的錢，我會在約定期限內還你的！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 의뢰는 다른 사람 알아 보라고, 영감님.","JPN":"この依頼は他を当たってくれ。","ENG":"So, find someone else for the job, old man.","TWN":"老頭，這個委託我看你還是找別人接吧！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"아니, 사장님! 리플레이서 사태 때 받은 보상금도 제인 언니한테 털렸으면서 무슨 재주로 갚겠다는 거예요?","JPN":"あの、社長！　リプレイサー事件の時に頂いた報奨金は全部ジェーンさんに持ってかれたのに、どうやって返すつもりですか？","ENG":"Come on, Boss! All the compensation money you got from the Replacer incident was stolen by Jane. How are you ever going to pay him?","TWN":"喂，老闆！克隆集團事件的獎金都被珍妮姊拿走了，你是要拿什麼還啦？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"지금 빚 걱정보다 파산 걱정이 더 급한 거 몰라요?","JPN":"今は借金どころか、破産寸前ですよ！？","ENG":"Don't you know we're on the verge of bankruptcy?","TWN":"我們公司現在不是負債而已喔，是已經要宣告破產了啦，你還搞不清楚狀況！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"이런 후진 사무소까지 찾아와서 의뢰를 주신다는데 넙죽 받아 챙겨야죠!","JPN":"こんなオンボロ事務所まで来ていただいて依頼してくれたんですよ、受けてください！","ENG":"Mr. Helmsworth came all the way to this backwater to hire us. You've got to accept the job!","TWN":"人家這麼好心把工作上門，你應該要立刻答應吧！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"흠……. 뭐, 선택은 본인 자유지.","JPN":"ふむ……まあ、決めるのは本人の自由だからな。","ENG":"Well, the choice is yours.","TWN":"嗯……總之決定權在你。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"건물 한 채 세우고도 남을 의뢰비를 포기하다니, 이 친구도 언젠가 거물이 되겠군.","JPN":"ビル一棟くらいなら余裕で建てられる報酬の依頼を断るなんて、贅沢な奴だ。","ENG":"I didn't know you were bold enough to give up a whole building's worth of money. I'm sure you'll be a big shot one day.","TWN":"竟然放棄蓋一棟房子都還有剩的委託費不要，我看你將來肯定是位了不起的人物。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"待て。","ENG":"Hang on.","TWN":"等一下。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L21_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"뭐지?","JPN":"何だ？","ENG":"What?","TWN":"幹嘛？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다시 생각해 봤는데 경호라는 건 사람을 지키는 아주 중요한 일이잖아?","JPN":"改めて考えてみたが、警護というのは人を守るとても重要な仕事だろ？","ENG":"On second thought, being a bodyguard is a very important job.","TWN":"我仔細想了一下，守衛的工作就是保護人身安全，"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"언제 어디서 닥칠지 모를 위험에 대비하려면 나 같은 두뇌파 용병이 나서 줘야지.","JPN":"いつどこで迫ってくるかわからない危険に備えるためには、俺のような頭脳派の傭兵が必要だろう。","ENG":"To predict and prepare for all possible dangers, you need someone smart, like the Intelligent Mercenary.","TWN":"而且要防範突如其來的危險，這麼重要的事，我這個頭腦派傭兵自然是當仁不讓囉！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"와아. 자본주의의 뻔뻔함.","JPN":"わあ、見事なまでに資本主義の敗北者ですね。","ENG":"Wow, look at that shameless capitalist!","TWN":"哇～還真敢講，明明就看在錢的份上。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"피자 두 조각 가지고 궁시렁거리던 건 자본주의의 째째함이냐?","JPN":"たかがピザ2ピースで渋っていたのは誰だったかな？","ENG":"Then what are you, a stingy capitalist who won't share a few slices of pizza?","TWN":"連兩片披薩都不肯分我的人，有什麼資格說話！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"좋아. 그럼 의뢰서는 여기 두고 가지.","JPN":"よし。じゃあ、依頼書はここに置いておく。","ENG":"Alright, then I'll leave the request here.","TWN":"很好，那委託書我就擱在這囉～"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그리고 경호 의뢰라고 너무 얕보진 마라.","JPN":"あと、警護依頼だからって舐めちゃあいかんぞ。","ENG":"But don't think it's just a simple bodyguard job.","TWN":"另外好心提醒你，別以為是守衛就可以便宜行事。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"음……? 뭐 의뢰주님께서 맨 VS 다이브 보고 이면세계라도 탐험하고 싶어지신 건가?","JPN":"うん……？　依頼主はマンVSダイブの映画でも観て、裏世界の探検でもしたくなったのか？","ENG":"Huh? Why not? Does our employer want to explore the Counterside? Did he watch an episode of Man vs. Dive or something?","TWN":"嗯……？委託人不會是看完曼恩VS潛水後想到異界冒險吧？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"망신당하지 않게 조심하란 얘기지.","JPN":"恥さらしにならないように気をつけろってことだ。","ENG":"No. Just be careful not to embarrass yourself.","TWN":"我只是提醒你小心不要把事情搞砸。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"경호를 의뢰한 건…….","JPN":"警護を依頼したのは……","ENG":"He wanted to hire you...","TWN":"對方之所以會需要守衛……"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"<color=#ffd34c>괴도 르블랑</color>의 예고장 때문이니까.","JPN":"<color=#ffd34c>怪盗ルブラン</color>の予告状のせいだからな。","ENG":"because he received an advance notice from <color=#ffd34c>LeBlanc the Thief</color>.","TWN":"是因為<color=#ffd34c>怪盜布勒朗</color>的預告信。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};